var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"제 2 난민지구 침식지대\\n<color=#ffd34c>비정규 수색 분대</color> 정기소탕 의뢰 수행 중\\nCSE Level 2+","JPN":"第2難民地区侵食地帯\\n<color=#ffd34c>非正規捜索分隊</color>定期掃討依頼遂行中\\nCSE Level 2+","ENG":"Corrupted Area, 2nd Refuge District\\n<color=#ffd34c>Irregular Search Squad</color> on a Regular Subjugation Mission\\nCSE Level 2+","TWN":"第2難民區侵蝕地區\\n<color=#ffd34c>非正式搜查分隊</color>執行定期掃蕩委託中\\nCSE Level 2+"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"다들 들어 봐. 바깥이 잠잠해졌어.","JPN":"おい、待て。外が静かになったぞ。","ENG":"Guys, listen. I don't hear anything outside anymore.","TWN":"你們聽，外面沒聲音了。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"침식체 놈들, 포기하고 가 버린 거 아냐?","JPN":"侵食体のやつら、諦めて帰ったんじゃないか？","ENG":"The C.O.s must have given up and left.","TWN":"侵蝕體是不是放棄走掉啦？"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"히익……!","JPN":"ひいっ……！","ENG":"Heek...!","TWN":"嗚嗚……！"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L11_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"반대편 벽에 바짝 붙어 있으세요. 그러다 다 같이 죽을 수도 있어요.","JPN":"反対側の壁に固まっててください。下手したら皆ここで死ぬかもしれません。","ENG":"Stay close to the opposite wall, or we could all die together.","TWN":"請貼緊對面牆壁，否則大家很可能會一起死！"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L12_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"그럼 여기 계속 있자는 뜻이야? 우리가 이 비좁은 데 갇힌 지 얼마나 지났는데?","JPN":"ずっとここで待機しろと？　この狭い場所にに閉じ込められてどれだけ経つと思ってんだ？","ENG":"Are you saying we should stay here? Don't you know how long we've been cooped up in this tiny place?","TWN":"意思是叫我們繼續待在這裡嗎？我們被困在這個狹小的空間裡都多久了？"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"조금만 더 참아요. 정기 연락이 끊긴 지 오래됐으니까 곧 지원을 보내 줄 거예요.","JPN":"もう少し我慢してください。ずっと定期連絡ができてないから、向こうも気づいてすぐ支援を送ってくれるはずです。","ENG":"Let's be patient a little longer. We've missed quite a few regular reports. Help will be here soon.","TWN":"請再忍耐一下，我們這麼長時間沒有回報消息，他們一定很會就會派支援來的！"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"지원을 보내?","JPN":"支援を送る？","ENG":"Help?","TWN":"派支援來？"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"누가? 우리 같은 떨거지들도 겨우 고용한 저 가난뱅이들이?","JPN":"誰が？　俺たちみたいな連中を辛うじて雇えたぐらいの、あの金ないやつらがか？","ENG":"From whom? Those paupers who can barely afford third-rate mercenaries like us?","TWN":"誰派？那些只請得起我們這種傭兵的窮鬼嗎？"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"의뢰주라고 불러요. 앞으로도 용병 일 계속 하고 싶으면.","JPN":"依頼主、です。これからも傭兵やっていきたいなら、言葉には気をつけてください。","ENG":"You'd better call them clients if you want to stay in business.","TWN":"請稱呼他們為委託人，如果你還想繼續當傭兵的話。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"안 해! 아니, 못 하겠지! 여기서 죽을 텐데!","JPN":"しねえよ！　いや、できねえだろうな！　どうせここで死ぬんだし！","ENG":"No, I'm not gonna! I probably couldn't do it even if I wanted to. Because I'm going to die here!","TWN":"不當了啦！不，是當不了！我都要死在這裡了！"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はぁ……","ENG":"*Sigh...*","TWN":"哀……"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"통신기는 어때요? 고칠 수 없겠어요?","JPN":"通信機の様子は？　直せそうですか？","ENG":"How's the radio? Can you fix it?","TWN":"通訊器怎麼樣？修不好嗎？"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_SL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SHOTGUN_SL_NULL_NULL","text":{"KOREA":"글렀어. 부품이라도 하늘에서 뚝 떨어지면 모를까.","JPN":"駄目だ。空から部品が降りてこない限りは。","ENG":"No, unless it rains replacement parts.","TWN":"沒辦法，除是有天外突然飛來的零件吧？"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_SL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_10"},{"id":"L25_1","type":"dialog","speaker":"SHOTGUN_SL_NULL_NULL","text":{"KOREA":"구조 신호는 계속 보내고 있지만, 이 강도로는 침식지대 밖까지 닿지 않을 거야.","JPN":"救助信号は送り続けてるけど、この程度じゃ侵食地帯の外にまでは届かないだろうな。","ENG":"I've been sending distress signals, but I doubt they're strong enough to make it outside the Corrupted Area.","TWN":"雖然一直有在發求救訊號，但依照這個強度，可能無法傳達到侵蝕地區之外的地方。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_SL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"작전 중이던 다른 용병들이 신호를 받고 오길 바라야겠네요.","JPN":"作戦中の他の傭兵たちが信号に気づいて、ここに来てくれることを祈るしかありませんね。","ENG":"Then, let's hope other mercs in the area detect our signals and come to our rescue.","TWN":"現在只能期待作戰中的其他傭兵，能收到訊號來救我們。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHOTGUN_SL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"왜, 아예 관리국 연합함대가 온다고 하지 그래?","JPN":"ハッ、せっかくだから管理局の連合艦隊でも待ってたらどうだ？","ENG":"Just wait for the Administration coalition fleet, why don't you?","TWN":"是怎樣？你怎麼不乾脆說管理局聯合艦隊會來救我們？"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"이딴 돈도 안 될 데를 들쑤시고 다니는 멍청이들은 우리뿐이라고! 당신네 세상은 그렇게 희망차?!","JPN":"そもそも金にもならねえこんな場所に来てるやつらなんて、俺たちぐらいしかいねえんだし、希望なんて持てるかよ！","ENG":"Get real. We're the only ones stupid enough to come to places like this that have no booty whatsoever.","TWN":"像這種鳥不生蛋的地方，只有我們這種蠢蛋會來！你們的世界還真是充滿希望呢？！"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"그 카운터 놈 말을 믿는 게 아니었어. C급 주제에 거들먹거리더니 제일 먼저 죽었잖아…….","JPN":"あのカウンターを信じるんじゃなかった。C級のくせに偉そうなこと言って、先に死にやがって……","ENG":"I should never have believed that Counter. He was only Grade C, but acted as if he was much better. And he was the first to die…","TWN":"根本不該相信那個制裁者的話！不過是C級制裁者就在那邊耀武揚威的，結果第一個死的就是他……"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"죽은 사람 욕하는 데 힘빼지 마요. 제가 챙길 수 있는 사람은 한 명뿐이니까.","JPN":"死人への悪口に体力を費やすのはよくないですよ。私は1人の世話だけで精一杯ですし。","ENG":"Don't waste your energy on someone who's already dead. I can only take care of one person.","TWN":"請不要把力氣浪費在辱罵死人身上，我只能顧一個而已。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STINGER_FOX_NULL_SHORT","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"STINGER_FOX_NULL_SHORT","text":{"KOREA":"후우……. 후우우…….","JPN":"ふう……ふうう……","ENG":"Whew... Whewww...","TWN":"呼呼……呼呼呼……"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STINGER_FOX_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"……그 여자, 댁 일행이라고 했지? 아까부터 신경 쓰이게 왜 저래?","JPN":"……その女、お前の連れだろ？　さっきから何してるんだ？","ENG":"That woman. She's with you, right? What's wrong with her? Why is she doing that?","TWN":"……那個女的跟你是一夥的吧？她從剛剛就一直那樣欸？"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"공포증을 완화하려고 호흡을 가다듬는 거예요.","JPN":"恐怖症の症状を和らげるために、呼吸を整えているんです。","ENG":"She's just trying to breathe through her fears.","TWN":"她在調整吸呼舒緩恐懼症的症狀。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STINGER_FOX_NULL_SHORT","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"공포증이라고? 설마 좁은 데 있으면 발작하는 그런 거?","JPN":"恐怖症？　まさか、狭いところで発作が起きるあれか？","ENG":"Fears? Why? Is she claustrophobic or something?","TWN":"恐懼症？該不會是在狹窄的空間就會發作的那個吧？"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"비슷해요. 하늘을 봐야 진정되는데 이렇게 사방이 막힌 곳에서는 어렵거든요.","JPN":"似たようなものです。空を見れば落ち着くんですが、こんなに四方が塞がれた場所ではなかなか難しくて。","ENG":"Kind of. She doesn't feel comfortable when she can't see the sky above her.","TWN":"類似。她要看著天空才能冷靜下來，但在這種四周都被圍堵住的地方有困難。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"하, 패잔병에다 환자까지 계셨단 말이지.","JPN":"ハッ、敗残兵に患者までいるのか。","ENG":"Great, we're stranded and one of us is sick.","TWN":"哈，我們這群當中不是殘兵敗將，就是病人呢！"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"우릴 구하러 오지 않을 이유가 하나 더 생겼네.","JPN":"助けが来ない理由がまた1つ増えたな。","ENG":"One more reason we're unsalvageable.","TWN":"現在又多一個沒人會來救我們的原因了。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"같이 유언이나 적어 둘까? 그럼 전사자 리뷰 채널에 오늘의 쪼다들이라고 이름이라도 걸리겠지?","JPN":"一緒に遺言でも残さないか？　少なくとも戦死者チャンネルで、本日の間抜けどもってことで名前でもあげてくれるかもしれねえぞ。","ENG":"Why don't we write a will already? Who knows? The fallen soldier review channel might post our names as the Fools of the Day.","TWN":"要一起寫遺言嗎？至少能在暗影戰死者評論的頻道裡，留下今天蠢蛋之名？"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"진정해요. 다른 사람들한테 스트레스를 푼다고 상황이 나아지진 않아요.","JPN":"落ち着いてください。他人に八つ当たりしたところで状況は改善しません。","ENG":"Settle down. Taking your anger out on others won't change your situation.","TWN":"冷靜點，就算把情緒發洩在別人身上，情況也不會好轉。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"그래, 미안해 죽겠수다! 댁 같은 베테랑처럼 침착하지 못해서!","JPN":"はいはい悪かったな！　俺はベテラン様みたいに冷静にはなれないんだ！","ENG":"Well, I'm sorry I can't be as calm as a veteran like you!","TWN":"是啊，我真是罪該萬死！沒辦法像你這種老鳥一樣冷靜！"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"그런데 싫은 걸 어떡해? 죽기 싫은 걸 어떡하냐고?","JPN":"だって仕方ないだろ？　死にたくないんだよ！","ENG":"But I can't help it. I hate this. I just don't want to die!","TWN":"但我就不想啊？我就不想死啊，能怎麼辦？"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"기껏 장비도 스틸레인제로 새로 맞췄는데……. 이딴 거지 같은 의뢰는 괜히 받아 가지고……!","JPN":"装備もスチールレイン製に変えたばっかなのに……こんなクソみたいな依頼は受けるんじゃなかった……！","ENG":"I only recently upgraded my gear to the Steel Lane models. Gah, I should never have accepted this worthless job in the first place!","TWN":"好不容易才新換上這麼好的裝備……結果接到這種不賺錢的爛委託……！"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STINGER_FOX_NULL_SHORT","text":{"KOREA":"후윽……! 후우……! 후……!","JPN":"ふうっ……！　ふうっ……！　ふうっ……！","ENG":"Whew...! Whew...! Whew...","TWN":"嗚嗚……！嗚嗚……嗚嗚……！"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STINGER_FOX_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"STINGER_FOX_NULL_SHORT","text":{"KOREA":"공습 경보……. 때까치 놈들이야. 놈들이 분명 그 날처럼, 모래 폭풍처럼 몰려와서…….","JPN":"空襲警報……モズのやつらだよ。あの日のように……やつらが、砂嵐のように押し寄せてきて……","ENG":"The air raid siren... Butcherbirds. They'll roll in like a sandstorm, just like they did on that day...","TWN":"空襲警報……是那些伯勞鳥！他們一定會像那天一樣，像暴風般席捲而來……"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STINGER_FOX_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"그놈들은 여기 없어.","JPN":"ここにやつらはいない。","ENG":"They're not here.","TWN":"他們不在這裡。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STINGER_FOX_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"그러니 방아쇠에서 손가락 떼. 조금만 더 참으면 나갈 수 있을 거야.","JPN":"だから引き金から手を離すんだ。もう少し我慢すれば出られるはずだ。","ENG":"So, keep your finger off the trigger. We will get out of here soon.","TWN":"可以把你的手指從板機上拿開，再忍耐一下，我們一定可以出去的。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STINGER_FOX_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"젠장! 빌어먹을 침식체들아! 죽을 때는 곱게 죽게 내버려 둬!","JPN":"ちくしょう！　このクソ侵食体ども！　せめて安らかに死なせてくれよ！","ENG":"Goddamnit, you stupid C.O.! At least let us die peacefully!","TWN":"該死！可惡的侵蝕體！ 就不能讓我們好死嗎！"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"잠깐……. 목소리 좀 낮춰 봐요.","JPN":"待って……声をおさえてください。","ENG":"Wait. Lower your voice.","TWN":"等等……小聲一點。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"방금 들린 울음소리……. 위협하는 게 아니에요. 경계하는 거지.","JPN":"今の鳴き声…….威嚇じゃなくて、警戒しているようです。","ENG":"The way they howled just now... It wasn't threatening but rather wary.","TWN":"剛剛聽見的聲音……不是威脅，而是警戒。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"뭐? 그게 뭐가 다른데?","JPN":"は？　何が違うんだよ。","ENG":"Wary of what? What makes it different from the other times?","TWN":"啥？差別是什麼？"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"위협은 공격할 때 하는 행동이에요.","JPN":"威嚇は攻撃の時にすること。","ENG":"They sound threatening when they attack.","TWN":"威脅是攻擊時會有的行為。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"하지만 경계는…….","JPN":"でも、警戒は……","ENG":"They sound wary when they're...","TWN":"警戒則是……"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"……두려워할 때 하는 행동이죠.","JPN":"……何かに恐れている時の行動です。","ENG":"...Terrified.","TWN":"……害怕時會有的行為。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"여기 있었군. 구조 신호가 약해서 한참을 찾았어.","JPN":"ここにいたのか。救助信号が弱くて、捜すのに苦労したぞ。","ENG":"There you are. Your distress signals were so weak that it took a while to find you.","TWN":"原來在這裡。因為求救訊號有點弱，所以花了點時間才找到這裡。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"어……?","JPN":"えっ……？","ENG":"Err...","TWN":"請問……？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"카, 카운터……세요?","JPN":"か、カウンター……ですか？","ENG":"A-are you a... Counter?","TWN":"您……是制裁者？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"조디악 나이츠 블루시프트의 단장, 에스테로사 드 슈발리에다.","JPN":"ゾディアックナイツ：ブルーシフトの団長、エステロサ・ド・シュヴァリエだ。","ENG":"I am Esterosa de Chevalier, the captain of the Zodiac Knights: Blue Shift.","TWN":"我是十二宮騎士團：藍移的團長 艾斯特洛索。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"늦어서 미안하군. 혹시 이 중에 부상자가 있는가?","JPN":"遅れてすまない。この中に負傷者はいるか？","ENG":"I'm sorry I couldn't come sooner. Is any one of you injured?","TWN":"很抱歉來晚了，有人受傷嗎？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"음……?","JPN":"ん……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"아까부터 나를 따라오던데, 할 이야기가 있나?","JPN":"先程から私の後をつけてきてるようだが、何か話があるのか？","ENG":"You've been following me. Do you have something to say to me?","TWN":"你從剛剛就一直跟著我，是有話要跟我說嗎？"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"보수도 나누지 않고 가는 건가요?","JPN":"報酬も分けてもらわずに帰るんですか？","ENG":"Don't you want a share of our profit?","TWN":"你就這樣走掉，是不打算分錢嗎？"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"아, 그대들이었군.","JPN":"あっ、君たちだったのか。","ENG":"Ah, it's you.","TWN":"喔，原來是你們。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"이 지역 아이들인 줄 알았어. 어린 아이들 눈에는 이 망토가 멋있어 보이는지 자주 따라오거든.","JPN":"ここの地域の子どもたちなのかと思った。このマントが子どもには格好よく見えるようで、よくついて来られるもんでな。","ENG":"I thought you were kids in this area. Little children often follow me because I guess my cape looks awesome to them. ","TWN":"我還以為你們是住在這附近的小朋友，因為覺得這件披風很帥才一直跟著我。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"아이들 눈에도 신기하게 보이겠죠. 옛날 이야기 속 기사님이 나타났으니까.","JPN":"子供たちにとっても不思議でしょうね。おとぎ話に出てくる騎士様が現れたようなものですから。","ENG":"They probably think you're awesome. You're a modern-day knight in shining armor.","TWN":"小朋友應該也覺得很神奇吧？你就好像從故事書裡走出來的騎士一樣。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그렇게 얘기해 주니 부끄럽군. 아직 일화를 남길 만한 일은 해낸 적이 없는데 말이야.","JPN":"そう言われると恥ずかしいな。まだ逸話が残るようなことはしていないが。","ENG":"I'm flattered. But I haven't achieved any veritable heroic feats, just yet.","TWN":"聽你這麼說有點不好意思，雖然我根本還沒做過什麼，可以真正寫進故事書裡的事。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그런데 보수를 나눈다니 무슨 뜻인가?","JPN":"ところで、報酬を分けるとはどういうことだ？","ENG":"By the way, what do you mean if I want a share of your profit?","TWN":"不過你剛說的分錢是什麼意思？"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"구조를 받지 않았다면 실패할 의뢰였으니까.","JPN":"救助してもらえなかったら、依頼は失敗してたはずだ。","ENG":"We would have failed our mission if you didn't come to our rescue.","TWN":"要不是你來救我們，我們也無法完成委託。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"의뢰비가 아무리 헐값이라도 구조자 측에게 높은 배율로 분배하는 게 업계 불문율이야.","JPN":"だからどんなにちっぽけな報酬でも、救助してもらった時は救助者に有利な割合で分けるのが暗黙のルールだ。","ENG":"It's the unwritten rules of the industry that you give your rescuer a large chunk of your payment, no matter how cheap your mission was.","TWN":"所以就算委託費只有一點點，還是要分給救我們的人很高的％數，這是業界的潛規則。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그럼 그 돈은 고장난 장비를 수리하는 데 쓰도록.","JPN":"なら、そのお金は壊れた装備の修理に使ってくれ。","ENG":"Okay, then I want you to use my share to repair your broken gear.","TWN":"那就把那些錢拿去修理壞掉的裝備吧！"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"내 몫을 바라고 한 일은 아니다. 기사단의 사명대로 위험에 처한 이들을 도왔을 뿐이지.","JPN":"見返りを求めてやったことではない。私は騎士団の使命に従い、危機に陥った者たちを助けただけだ。","ENG":"I didn't save you because I wanted something in return. I only did it according to the mission of the order.","TWN":"我這麼做的目的不是要分錢，而是因為騎士團的使命，就是要拯救處於危難中的人。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"정말 한 푼도 안 받는다고? 카운터라면 적어도 이터니움은 필요할 거 아냐?","JPN":"本当にいらないのか？　カウンターならエタニウムぐらいは必要だろ？","ENG":"Are you sure you don't want anything? You're a Counter. Don't you at least want some Eternium?","TWN":"你真的一毛錢都不要？制裁者起碼會需要永恆之金吧？"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"우리는 가문들이 조달해 주는 활동비로도 충분하다.","JPN":"私は家門から調達してもらっている予算で足りている。","ENG":"We get enough financial support from our families.","TWN":"我們有家族分配的活動經費便已足夠。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"보다시피, 싸우는 방식이 다른 이들보다 수수한 편이라서 말이야.","JPN":"見てわかると思うが、戦い方が他の者たちより地味なもんでな。","ENG":"Also, as you can see, we don't need a lot of things to fight, unlike some others.","TWN":"而且如你所見，我戰鬥的方式和他們比起來，是那麼地樸實無華。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"……조디악 나이츠라고 했죠?","JPN":"……ゾディアックナイツ、でしたっけ？","ENG":"...The Zodiac Knights, right?","TWN":"……你說你是十二宮騎士團的對吧？"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"직접 만나 보니 소문대로네요. 좋은 쪽으로든, 안 좋은 쪽으로든.","JPN":"直接会ってみたら、噂通りですね。いい意味でも、悪い意味でも。","ENG":"I've heard many bad and good things about you, and you're just as I've heard.","TWN":"先不論是好或壞，但果然跟傳聞所說的一樣。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"의외로군. 좋은 소문도 있던가?","JPN":"それは心外だな。いい噂もあるのか？","ENG":"That's unexpected. I didn't know people said good things about us.","TWN":"真令人意外，有好的傳聞嗎？"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"뭐, 태스크 플래닛 리뷰 중에 좋은 얘기라곤 착한 호구라는 것 정도지…….","JPN":"まあ、タスクプラネットでいいレビューが書かれてるって言っても、お人よしってことぐらいだな……","ENG":"Well, the only good thing I read on the reviews of Task Planet is that you're fearless, goodhearted, and... naive.","TWN":"嗯…在任務星球評論中，好話頂多就是善良的冤大頭……"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"그래도 이제 걱정 마. 우리 모두 네 활약을 똑똑히 봤잖아.","JPN":"でも心配するな。俺たちがお前の活躍をこの目で見たからな。","ENG":"But don't worry now. We've all witnessed what you can do.","TWN":"不過你放心吧！我們都有親眼見識到你的厲害！"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L25_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"실력만 확실하면 인성이고 나발이고 상관없는 게 이 바닥이야. 원한다면 내가 아는 선배도 소개해 줄 수 있어.","JPN":"この業界は腕さえ確かなら、性格がどうとかは関係ない。よかったら知り合いの先輩も紹介してやるぞ。","ENG":"In this line of business, nothing else matters so long as you've got skill. I can introduce you to a close colleague of mine if you want.","TWN":"這個世界是看實力的，管你是好人壞人，還是需要我介紹個認識的前輩給你？"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"고마운 제안이군. 하지만 사양하겠다.","JPN":"それはありがたい。だが、遠慮しておこう。","ENG":"I appreciate the offer, but no, thank you.","TWN":"謝謝你的好意，我心領了。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"아니, 대체 왜?","JPN":"なんでだ？","ENG":"Why not?","TWN":"為什麼？"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"너보다 한참 못난 녀석들한테 광대 취급 당하는 게 싫지도 않은 거야?","JPN":"自分より遥かに劣るやつらがバカ扱いしてるのに、悔しくないのか？","ENG":"Don't you hate being treated like a clown by those beneath you?","TWN":"被那些比你還沒用的傢伙說是小丑，難道你不生氣嗎？"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"비슷한 말은 여러 번 들었다만, 두려움의 대상보다는 농담거리인 편이 더 낫지 않나?","JPN":"そういう話はよく聞いているが、恐れられるよりは冗談のネタにされるほうがマシだろう？","ENG":"I've heard that before, but I'd rather be a subject of mockery than of fear.","TWN":"類似的話我已經聽過許多次，但與其成為別人害怕的對象，不如成為別人開玩笑的對象。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"자기를 해코지할 수 있는 무기를 들고 다니는데도 피하거나 경계하지는 않으니까.","JPN":"人を傷つけられる武器を持ち歩いていてたとしても、避けられたり警戒されたりしなくて済むから。","ENG":"People are not afraid of me even though I'm carrying a weapon that can hurt them.","TWN":"因為這樣就算我拿著武器，別人也不會對我有防備或是戒心。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That's...","TWN":"可是……"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"기사의 명예란 맹세에 어긋나지 않는 길을 걸으면 자연스레 빛나는 법이다.","JPN":"騎士の名誉とは、誓った道をひたすら歩けば自ずと輝くものだ。","ENG":"As a knight, I believe I can raise my honor just by doing what I do.","TWN":"只要走在不違反騎士榮譽的路上，自然就會發光。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그러면 이만 가 보겠다. 다른 단원들이 기다리고 있어.","JPN":"では、これで失礼する。他の団員たちが待っているからな。","ENG":"Now, I'd better go. The others are waiting.","TWN":"那我就先告辭了，其他團員還在等我呢。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"아직 어린 나이인데……. 신기할 만큼 의젓하네.","JPN":"まだ若いのに……驚くほどしっかりしてる。","ENG":"She's so young, yet remarkably mature.","TWN":"看她年紀輕輕的……卻那麼穩重。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"무슨 교육을 받고 커야 저렇게 자라는 걸까…….","JPN":"いったい、どういう教育を受けて育ったんだろう……","ENG":"I wonder what kind of training she received growing up...","TWN":"從小要受什麼樣的教育，長大才能跟她一樣呢……"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"저기…….","JPN":"おい……","ENG":"Hey...","TWN":"那個……"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SNIPER_FOX_NULL_NULL","text":{"KOREA":"응?","JPN":"はい？","ENG":"Yeah?","TWN":"嗯？"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_NULL","text":{"KOREA":"세상이라는 거……. 의외로 내가 생각했던 것보다 더 희망찬가 봐.","JPN":"世の中には……思ってたより意外と、まだ希望があるんだな。","ENG":"It seems this world... It's not as bleak as I thought.","TWN":"或許這個世界……比我想像中還有值得盼望的地方呢？"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SNIPER_FOX_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};